        object: crSetSnapshot,
        participant: crSetSnapshot,
        provider: crSetSnapshot,
        result: crSetSnapshot,
        startTime: '',
        target: crSetSnapshot,
        ...defaultShape,
      } as unknown as Partial<Shape>,
      {
        actionProcess: 'set',
        agent: 'set',
        error: 'set',
        instrument: 'set',
        location: 'set',
        object: 'set',
        participant: 'set',
        provider: 'set',
        result: 'set',
        target: 'set',
        ...crdtProperties,
      } as Partial<
        Record<Extract<keyof Shape, string>, 'text' | 'set' | 'list' | 'map'>
